<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<style>
    /* --- 混沌至高神性主题 (升级版特效) --- */
    :root {
        --void-bg: #050508;
        --void-panel: rgba(15, 15, 20, 0.85);
        --god-gold: #ffd700;
        --god-gold-glow: rgba(255, 215, 0, 0.6);
        --star-purple: #9d4edd;
        --star-purple-glow: rgba(157, 78, 221, 0.6);
        --text-main: #e8e8e8;
        --text-dim: #888;
        --glass-border: 1px solid rgba(255, 215, 0, 0.3);
        --neon-cyan: #00f3ff;
        --neon-pink: #ff007c;
    }

    .god-interface {
        font-family: 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
        background: radial-gradient(circle at center, rgba(20,20,35,0.9) 0%, rgba(5,5,10,0.95) 100%);
        color: var(--text-main);
        padding: 20px;
        border-radius: 15px;
        position: relative;
        overflow: hidden;
        border: var(--glass-border);
        /* 神性呼吸光效 */
        box-shadow: 0 0 20px rgba(157, 78, 221, 0.3), inset 0 0 30px rgba(255, 215, 0, 0.1);
        animation: god-breath 6s infinite alternate ease-in-out;
        backdrop-filter: blur(10px);
        -webkit-backdrop-filter: blur(10px);
    }

    @keyframes god-breath {
        0% { box-shadow: 0 0 20px rgba(157, 78, 221, 0.3), inset 0 0 20px rgba(255, 215, 0, 0.05); border-color: rgba(157, 78, 221, 0.3); }
        100% { box-shadow: 0 0 40px rgba(255, 215, 0, 0.4), inset 0 0 50px rgba(157, 78, 221, 0.2); border-color: rgba(255, 215, 0, 0.6); }
    }

    /* 全息扫描线 (高维观测感) */
    .scanlines {
        position: absolute;
        top: 0; left: 0; width: 100%; height: 100%;
        background: linear-gradient(to bottom, rgba(255,255,255,0), rgba(255,255,255,0) 50%, rgba(0,0,0,0.1) 50%, rgba(0,0,0,0.1));
        background-size: 100% 4px;
        z-index: 10;
        pointer-events: none;
        opacity: 0.6;
    }

    /* 动态混沌漩涡背景 */
    .stars {
        position: absolute;
        top: -50%; left: -50%; width: 200%; height: 200%;
        background:
            radial-gradient(circle at center, transparent 20%, #050508 70%),
            conic-gradient(from 0deg at 50% 50%,
                rgba(157, 78, 221, 0.1) 0deg,
                rgba(255, 215, 0, 0.05) 60deg,
                transparent 120deg,
                rgba(157, 78, 221, 0.1) 180deg,
                rgba(0, 243, 255, 0.05) 240deg,
                transparent 300deg,
                rgba(157, 78, 221, 0.1) 360deg);
        animation: vortex-spin 40s linear infinite;
        z-index: 0;
        pointer-events: none;
        opacity: 0.8;
    }
    .stars::after {
        content: '';
        position: absolute;
        top: 0; left: 0; width: 100%; height: 100%;
        background-image:
            radial-gradient(1px 1px at 20px 30px, #fff, rgba(0,0,0,0)),
            radial-gradient(2px 2px at 40px 70px, rgba(255,215,0,0.8), rgba(0,0,0,0)),
            radial-gradient(1.5px 1.5px at 90px 40px, rgba(157,78,221,0.8), rgba(0,0,0,0));
        background-size: 150px 150px;
        animation: star-drift 20s linear infinite;
    }
    @keyframes vortex-spin { 100% { transform: rotate(360deg); } }
    @keyframes star-drift { 100% { transform: translateY(150px) rotate(10deg); } }

    .content-layer {
        position: relative;
        z-index: 20;
    }

    /* 剧情文本框增强 */
    .intro-text {
        font-size: 1.05em;
        line-height: 1.6;
        margin-bottom: 25px;
        text-shadow: 0 2px 5px rgba(0,0,0,0.8);
        white-space: pre-wrap;
        color: #e0e0ff;
        font-style: italic;
        padding: 18px;
        background: linear-gradient(90deg, rgba(0,0,0,0.7) 0%, rgba(0,0,0,0.3) 100%);
        border-left: 4px solid var(--god-gold);
        border-radius: 0 12px 12px 0;
        box-shadow: 5px 5px 15px rgba(0,0,0,0.5), inset 2px 0 10px rgba(255, 215, 0, 0.2);
        position: relative;
        overflow: hidden;
    }
    .intro-text::before {
        content: ''; position: absolute; top: 0; left: -100%; width: 50%; height: 100%;
        background: linear-gradient(90deg, transparent, rgba(255,215,0,0.1), transparent);
        animation: text-sweep 4s infinite;
    }
    @keyframes text-sweep { 100% { left: 200%; } }

    /* --- 汉堡菜单特效 --- */
    .hamburger-btn {
        position: absolute;
        top: 15px;
        right: 15px;
        font-size: 26px;
        background: none;
        border: none;
        color: var(--god-gold);
        cursor: pointer;
        z-index: 100;
        transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
