        height: 100%;
        background: rgba(8, 8, 12, 0.95);
        border-left: 2px solid var(--star-purple);
        transition: right 0.5s cubic-bezier(0.4, 0, 0.2, 1);
        z-index: 99;
        padding: 60px 20px 20px 20px;
        overflow-y: auto;
        box-shadow: -15px 0 40px rgba(0,0,0,0.9), inset 5px 0 20px rgba(157,78,221,0.2);
        backdrop-filter: blur(15px);
        -webkit-backdrop-filter: blur(15px);
    }
    .sidebar-menu.active { right: 0; }

    .sidebar-menu::-webkit-scrollbar { width: 4px; }
    .sidebar-menu::-webkit-scrollbar-track { background: transparent; }
    .sidebar-menu::-webkit-scrollbar-thumb { background: linear-gradient(var(--star-purple), var(--god-gold)); border-radius: 4px; }

    /* 自定义世界输入框 */
    .custom-input-group {
        display: flex;
        gap: 8px;
        margin-bottom: 20px;
        padding-bottom: 15px;
        border-bottom: 1px dashed rgba(157, 78, 221, 0.5);
    }
    .custom-input-group input {
        flex: 1;
        background: rgba(0,0,0,0.6);
        border: 1px solid rgba(157, 78, 221, 0.4);
        color: #fff;
        padding: 10px;
        border-radius: 6px;
        font-size: 0.9em;
        font-family: inherit;
        transition: all 0.3s;
    }
    .custom-input-group input:focus {
        outline: none;
        border-color: var(--god-gold);
        box-shadow: 0 0 10px var(--god-gold-glow);
        background: rgba(20,20,0,0.6);
    }
    .custom-input-group button {
        background: linear-gradient(45deg, var(--star-purple), #6a0dad);
        border: 1px solid rgba(255,255,255,0.2);
        color: #fff;
        padding: 0 12px;
        border-radius: 6px;
        cursor: pointer;
        font-weight: bold;
        transition: all 0.3s;
        box-shadow: 0 0 10px var(--star-purple-glow);
    }
    .custom-input-group button:hover {
        background: linear-gradient(45deg, #b266ff, var(--star-purple));
        box-shadow: 0 0 15px var(--star-purple), 0 0 5px #fff;
        transform: translateY(-1px);
    }

    .category-title {
        color: var(--god-gold);
        font-size: 0.9em;
        text-transform: uppercase;
        letter-spacing: 3px;
        border-bottom: 1px solid rgba(255, 215, 0, 0.3);
        padding-bottom: 5px;
        margin-bottom: 12px;
        text-shadow: 0 0 5px rgba(255,215,0,0.5);
    }
    .world-item {
