    }

    /* --- 观测池 (全息投影质感) --- */
    .observation-pool {
        background: radial-gradient(circle, rgba(20,20,40,0.6) 0%, rgba(0,0,0,0.8) 100%);
        border: 1px solid rgba(0, 243, 255, 0.2);
        border-radius: 12px;
        padding: 20px;
        margin-bottom: 25px;
        text-align: center;
        min-height: 220px;
        display: flex;
        flex-direction: column;
        justify-content: center;
        align-items: center;
        transition: all 0.5s;
        box-shadow: 0 10px 30px rgba(0,0,0,0.8), inset 0 0 20px rgba(0, 243, 255, 0.05);
        position: relative;
    }
    .observation-pool::before {
        content: ''; position: absolute; top: 0; left: 0; right: 0; height: 1px;
        background: linear-gradient(90deg, transparent, var(--neon-cyan), transparent);
        opacity: 0.5;
    }

    .world-preview-img {
        width: 100%;
        max-height: 180px;
        object-fit: cover;
