    .opt-btn.active[data-group="gender"][data-val="Futa"] { background: rgba(157, 78, 221, 0.15); border-color: var(--star-purple); color: #fff; box-shadow: 0 5px 15px rgba(157,78,221,0.4), inset 0 0 10px rgba(157,78,221,0.2); text-shadow: 0 0 5px var(--star-purple);}

    .opt-btn.active[data-group="target"][data-val="Female_Only"] { background: rgba(255, 0, 124, 0.15); border-color: var(--neon-pink); color: #fff; box-shadow: 0 5px 15px rgba(255,0,124,0.4); text-shadow: 0 0 5px var(--neon-pink);}
    .opt-btn.active[data-group="target"][data-val="Male_Only"] { background: rgba(0, 180, 216, 0.15); border-color: #00b4d8; color: #fff; box-shadow: 0 5px 15px rgba(0,180,216,0.4); text-shadow: 0 0 5px #00b4d8;}
    .opt-btn.active[data-group="target"][data-val="All"] { background: rgba(255, 215, 0, 0.15); border-color: var(--god-gold); color: #fff; box-shadow: 0 5px 15px rgba(255,215,0,0.4); text-shadow: 0 0 5px var(--god-gold);}

    .opt-btn.active[data-group="mode"][data-val="Adventure"] { background: rgba(220, 53, 69, 0.15); border-color: #dc3545; color: #fff; box-shadow: 0 5px 15px rgba(220,53,69,0.4); text-shadow: 0 0 5px #dc3545;}
    .opt-btn.active[data-group="mode"][data-val="Incognito"] { background: rgba(23, 162, 184, 0.15); border-color: #17a2b8; color: #fff; box-shadow: 0 5px 15px rgba(23,162,184,0.4); text-shadow: 0 0 5px #17a2b8;}
    .opt-btn.active[data-group="mode"][data-val="Hedonism"] { background: rgba(255, 193, 7, 0.15); border-color: #ffc107; color: #fff; box-shadow: 0 5px 15px rgba(255,193,7,0.4); text-shadow: 0 0 5px #ffc107;}

    /* --- 指南面板 --- */
    .dice-guide {
        border: 1px solid rgba(255,255,255,0.1);
        border-radius: 8px;
        margin-bottom: 20px;
        background: rgba(0,0,0,0.4);
        transition: all 0.3s;
    }
    .dice-guide[open] { border-color: rgba(157,78,221,0.4); box-shadow: 0 0 15px rgba(0,0,0,0.5); }
    .guide-summary {
        padding: 12px;
        cursor: pointer;
        color: var(--text-dim);
        font-size: 0.95em;
        display: flex;
        justify-content: space-between;
        align-items: center;
        transition: color 0.3s;
    }
    .guide-summary:hover { color: var(--god-gold); text-shadow: 0 0 5px rgba(255,215,0,0.5); }
    .guide-content {
        padding: 15px;
        border-top: 1px dashed rgba(255,255,255,0.1);
        font-size: 0.85em;
        color: #ccc;
        line-height: 1.6;
    }
    .rule-box {
        background: rgba(0,0,0,0.5);
        padding: 12px;
        border-radius: 6px;
        margin-top: 10px;
        font-family: monospace;
        border-left: 2px solid var(--star-purple);
    }

    /* --- 终极降临按钮特效 --- */
    .action-bar { margin-top: 15px; position: relative; }

    .start-btn {
        width: 100%;
        padding: 16px;
        background: linear-gradient(135deg, #ffd700, #ffa500, #ff8c00, #ffd700);
        background-size: 300% 300%;
        border: none;
        border-radius: 10px;
        color: #111;
        font-weight: 900;
        font-size: 1.25em;
        cursor: pointer;
        text-transform: uppercase;
        letter-spacing: 4px;
        transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        box-shadow: 0 5px 20px rgba(255, 215, 0, 0.4), inset 0 2px 5px rgba(255,255,255,0.5);
        position: relative;
