<script>
    // 状态存储与逻辑保持不变
    let config = {
        worldName: null,
        gender: 'Male',
        genderText: '男性',
        target: 'Female_Only',
        targetText: '仅限女性',
        mode: 'Hedonism',
        modeText: '享乐模式'
    };

    function toggleSidebar() {
        document.getElementById('sidebar').classList.toggle('active');
    }

    function updateWorldUI(name, desc, imgUrl) {
        config.worldName = name;
        document.getElementById('world-title').innerText = "『 " + name + " 』";
        document.getElementById('world-desc').innerText = desc;
        const imgEl = document.getElementById('world-img');
        if(imgUrl) {
            imgEl.src = imgUrl;
            imgEl.style.display = 'block';
            // 每次切换图片重置一下滤镜动画，增加科技感
            imgEl.style.animation = 'none';
            setTimeout(() => imgEl.style.animation = 'hologram-flicker 4s infinite', 10);
        }
        else { imgEl.style.display = 'none'; }
        checkReady();
    }

    function selectWorld(name, desc, imgUrl, el) {
        updateWorldUI(name, desc, imgUrl);
        document.querySelectorAll('.world-item').forEach(i => i.classList.remove('active'));
        if(el) el.classList.add('active');
        toggleSidebar();
    }

    function setCustomWorld() {
        const val = document.getElementById('custom-world-input').value.trim();
        if (val) {
            updateWorldUI(val, '未知的次元坐标。一切法则与命运，皆由至高神的意志重塑。', '');
            document.querySelectorAll('.world-item').forEach(i => i.classList.remove('active'));
            toggleSidebar();
        } else {
            alert('神明大人，请先输入您要撕裂的次元名称哦！');
        }
    }

    function setOption(group, val, text, btnEl) {
        document.querySelectorAll(`.opt-btn[data-group="${group}"]`).forEach(el => el.classList.remove('active'));
        btnEl.classList.add('active');

        if(group === 'gender') { config.gender = val; config.genderText = text; }
        if(group === 'target') { config.target = val; config.targetText = text; }
        if(group === 'mode') { config.mode = val; config.modeText = text; }
    }

    function checkReady() {
        const btn = document.getElementById('start-btn');
        if (config.worldName) {
            btn.disabled = false;
            btn.innerText = `撕裂晶壁 · 降临 ${config.worldName}`;
        }
    }

    function startGame() {
        if (!config.worldName) return;

        // 根据不同的模式，动态生成强制规则糊在AI脸上
        let modeRule = '';
        if (config.mode === 'Adventure') {
            modeRule = "【绝对规则：冒险模式】主角已主动封印全知全能与所有神力！请立刻为主角生成一个符合该世界观的普通凡人身份。在接下来的描写中，绝对不可使用任何神权、魔法或超能力，必须像凡人一样面对危险、遵守物理法则、感受痛觉！";
        } else if (config.mode === 'Incognito') {
            modeRule = "【绝对规则：微服模式】主角神力内敛，隐匿于凡尘。请像普通人一样正常体验剧情，绝不主动显露神明身份，但遇到极端情况可随心所欲掀桌子。";
        } else if (config.mode === 'Hedonism') {
            modeRule = "【绝对规则：享乐模式】主角神威全开！无视一切世界规则与逻辑，任何反抗皆可随手碾碎，尽情展现至高神的傲慢与力量。";
        }

        // 拼接发给AI的开局强指令，附带绝对规则
        const command = `/send [系统指令] 玩家已确认降临配置：
1. 目标世界：${config.worldName}
2. 肉体性别：${config.genderText} (god_status.gender: ${config.gender})
3. 猎物倾向：${config.targetText} (god_status.target_preference: ${config.target})
4. 游玩模式：${config.modeText} (god_status.play_mode: ${config.mode})

${modeRule}

请立刻按此配置与绝对规则，构建主角刚刚降临该世界的初始剧情，并在接下来的回复中通过 <UpdateVariable> 正确更新上述变量！ | /trigger`;

        if (typeof triggerSlash === 'function') {
            triggerSlash(command);
        } else {
            alert("未检测到酒馆环境，指令已生成：" + command);
        }
    }

</script>
</body>
</html>
