    .progress-fill.hp-crit { background-color: #e63946; background-image: linear-gradient(45deg, rgba(255,255,255,.15) 25%, transparent 25%, transparent 50%, rgba(255,255,255,.15) 50%, rgba(255,255,255,.15) 75%, transparent 75%, transparent); animation: stripe-move 0.5s linear infinite, blink-crit 1s infinite; }
    @keyframes blink-crit { 0%,100%{opacity:1;} 50%{opacity:0.6;} }
    .progress-fill.chaos { background-color: var(--purple); background-image: linear-gradient(45deg, rgba(255,255,255,.15) 25%, transparent 25%, transparent 50%, rgba(255,255,255,.15) 50%, rgba(255,255,255,.15) 75%, transparent 75%, transparent); }
    .progress-fill.durability { background-color: var(--item-green); background-image: linear-gradient(45deg, rgba(255,255,255,.15) 25%, transparent 25%, transparent 50%, rgba(255,255,255,.15) 50%, rgba(255,255,255,.15) 75%, transparent 75%, transparent); }
    @keyframes stripe-move { 0% { background-position: 0 0; } 100% { background-position: 20px 0; } }

    .scroll-list { max-height: 250px; overflow-y: auto; padding-right: 6px; }
    .scroll-list::-webkit-scrollbar { width: 5px; }
    .scroll-list::-webkit-scrollbar-track { background: rgba(0,0,0,0.3); border-radius: 3px;}
    .scroll-list::-webkit-scrollbar-thumb { background: rgba(157, 78, 221, 0.5); border-radius: 3px; }

    .item-card { background: var(--glass-bg); border: 1px solid rgba(255, 255, 255, 0.1); border-left: 3px solid var(--gold); border-radius: 6px; padding: 10px; margin-bottom: 8px; transition: 0.3s; box-shadow: 0 4px 6px rgba(0,0,0,0.3); position: relative;}
    .item-card:hover { transform: translateX(4px); background: rgba(40, 30, 60, 0.7); box-shadow: 0 6px 12px rgba(157, 78, 221, 0.2); }
    .item-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px; }
    .item-name { color: #fff; font-weight: bold; font-size: 13px;}
    .item-tag { font-size: 10px; padding: 2px 8px; border-radius: 12px; background: rgba(0, 0, 0, 0.5); color: var(--text-dim); border: 1px solid #444;}
    .apostle-stats { display: grid; grid-template-columns: repeat(3, 1fr); gap: 6px; font-size: 11px; }
    .mini-stat { text-align: center; padding: 4px; background: rgba(0, 0, 0, 0.4); border-radius: 4px; border: 1px solid rgba(255,255,255,0.05);}

    /* 装备专属样式 */
    .equip-actions { display: flex; gap: 5px; margin-top: 8px; }
    .equip-btn { flex:1; background: rgba(0,0,0,0.5); border: 1px solid #555; color: #ccc; border-radius: 4px; padding: 4px; font-size: 10px; cursor: pointer; text-align: center; transition: 0.2s;}
    .equip-btn:hover { background: rgba(255,255,255,0.1); color: #fff; border-color: #888;}
    .modifier-tag { font-size: 10px; color: var(--gold); font-style: italic; display: block; margin-top: 4px; text-shadow: 0 0 5px var(--gold-glow);}

    .dice-input { width: 100%; padding: 8px 12px; background: rgba(0, 0, 0, 0.5); border: 1px solid rgba(157, 78, 221, 0.5); border-radius: 6px; color: #fff; font-size: 12px; font-family: inherit; margin-bottom: 10px; transition: all 0.3s;}
    .dice-input:focus { outline: none; border-color: var(--neon-cyan); box-shadow: 0 0 10px rgba(0, 243, 255, 0.3); }
    .diff-row { display: flex; align-items: center; gap: 10px; margin-bottom: 10px; font-size: 12px; }
    .diff-input { width: 60px; padding: 4px 6px; background: rgba(0, 0, 0, 0.5); border: 1px solid var(--purple); border-radius: 4px; color: var(--neon-cyan); font-family: monospace; font-size: 14px; font-weight: bold; text-align: center; }
    .dice-btn { width: 100%; padding: 10px; background: linear-gradient(135deg, #4b0082, #7b2cbf); border: 1px solid #9d4edd; border-radius: 6px; color: #fff; cursor: pointer; font-weight: bold; letter-spacing: 2px; transition: all 0.2s;}
    .dice-btn:hover { background: linear-gradient(135deg, #5c00a3, #9d4edd); box-shadow: 0 0 15px rgba(157, 78, 221, 0.6); transform: translateY(-2px); }

    .quick-actions { display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px; padding-top: 12px; margin-top: 12px; border-top: 1px dashed rgba(255, 215, 0, 0.3); }
    .quick-btn { background: rgba(20, 20, 35, 0.8); border: 1px solid rgba(255, 255, 255, 0.1); color: var(--text-dim); padding: 8px 2px; border-radius: 6px; text-align: center; cursor: pointer; font-size: 11px; display: flex; flex-direction: column; align-items: center; gap: 4px; transition: 0.3s;}
    .quick-btn i { font-size: 16px; color: var(--purple); transition: all 0.3s; }
    .quick-btn:hover { background: rgba(255, 215, 0, 0.1); color: #fff; border-color: var(--gold); transform: translateY(-2px); box-shadow: 0 5px 10px rgba(0,0,0,0.5); }
    .quick-btn:hover i { color: var(--gold); text-shadow: 0 0 8px var(--gold-glow); }

    .hidden-by-mode { display: none !important; }

    /* ====== 音乐播放器 & 歌词 ====== */
    .music-module { margin-top: 12px; background: rgba(0, 0, 0, 0.4); border: 1px solid rgba(157, 78, 221, 0.3); border-radius: 8px; overflow: hidden; }
    .music-player { display: flex; align-items: center; gap: 10px; padding: 10px; border-bottom: 1px solid rgba(255, 255, 255, 0.05); }
    .music-btn { background: none; border: none; color: var(--neon-cyan); cursor: pointer; font-size: 20px; transition: 0.3s; padding: 0 5px; }
    .music-btn:hover { color: #fff; text-shadow: 0 0 8px var(--neon-cyan); transform: scale(1.1); }
    .music-info { flex: 1; font-size: 11px; color: var(--text-dim); display: flex; flex-direction: column;}
    .music-title { color: var(--gold); font-weight: bold; font-size: 12px; letter-spacing: 1px;}
    .volume-control { display: flex; align-items: center; gap: 5px; }
    .volume-slider { width: 60px; accent-color: var(--purple); cursor: pointer; }

    .lyrics-container { height: 60px; overflow: hidden; position: relative; padding: 5px 10px; background: rgba(0,0,0,0.2); }
    .lyrics-container::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 15px; background: linear-gradient(to bottom, rgba(10,10,15,0.9), transparent); z-index: 2; pointer-events: none;}
    .lyrics-container::after { content: ''; position: absolute; bottom: 0; left: 0; right: 0; height: 15px; background: linear-gradient(to top, rgba(10,10,15,0.9), transparent); z-index: 2; pointer-events: none;}

    .lyrics-wrapper { display: flex; flex-direction: column; align-items: center; transition: transform 0.4s ease-out; }
    .lyric-line { font-size: 11px; color: var(--text-dim); line-height: 20px; text-align: center; transition: all 0.3s; min-height: 20px; opacity: 0.6; }
    .lyric-line.active { font-size: 13px; color: var(--neon-pink); font-weight: bold; opacity: 1; text-shadow: 0 0 8px rgba(255, 0, 124, 0.6); transform: scale(1.05); }

    /* ====== 弹窗 ====== */
    .modal-overlay { position: absolute; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.8); backdrop-filter: blur(5px); display: none; justify-content: center; align-items: center; z-index: 100; opacity: 0; transition: opacity 0.3s; }
    .modal-overlay.show { display: flex; opacity: 1; }
    .modal-box { width: 90%; max-height: 80%; background: var(--bg-dark); border: 1px solid var(--neon-cyan); border-radius: 12px; box-shadow: 0 0 20px rgba(0, 243, 255, 0.3); display: flex; flex-direction: column; overflow: hidden; }
    .modal-header { padding: 12px; background: rgba(0, 243, 255, 0.1); border-bottom: 1px solid rgba(0, 243, 255, 0.3); display: flex; justify-content: space-between; align-items: center; color: var(--neon-cyan); font-weight: bold; }
    .modal-close { cursor: pointer; color: #fff; font-size: 16px; }
    .modal-body { padding: 12px; overflow-y: auto; display: flex; flex-direction: column; gap: 10px; }
    .cast-btn { background: rgba(0,0,0,0.5); border: 1px solid rgba(255,255,255,0.2); border-radius: 8px; padding: 10px; text-align: left; cursor: pointer; transition: all 0.2s; position: relative; overflow: hidden; }
    .cast-btn:hover { background: rgba(0, 243, 255, 0.15); border-color: var(--neon-cyan); }
    .cast-title { font-size: 13px; color: #fff; font-weight: bold; margin-bottom: 4px; display: flex; justify-content: space-between;}
    .cast-desc { font-size: 11px; color: #aaa; }
    .cast-btn.disabled { opacity: 0.5; cursor: not-allowed; pointer-events: none; border-color: #f00; }

    .toast { position: fixed; bottom: 20px; left: 50%; transform: translateX(-50%); background: rgba(10, 10, 15, 0.95); border: 1px solid var(--neon-cyan); color: var(--neon-cyan); padding: 8px 16px; border-radius: 20px; font-size: 12px; font-weight: bold; opacity: 0; pointer-events: none; transition: opacity 0.3s; z-index: 9999; box-shadow: 0 0 15px rgba(0, 243, 255, 0.4); text-transform: uppercase; }
    .toast.show { opacity: 1; }
  </style>

  <script type="module">
    let miraclesData = {};

    function sendToTavern(text) {
      try {
        const $ta = parent.$('#send_textarea');
        if ($ta.length > 0) {
          $ta.val(text);
          $ta[0].dispatchEvent(new Event('input', { bubbles: true }));
          setTimeout(() => { parent.$('#send_but').click(); }, 100);
        }
      } catch (e) { console.error('[GodPanel]', e); }
    }
    function copyToInput(text) {
      try {
        const $ta = parent.$('#send_textarea');
        if ($ta.length > 0) {
          $ta.val(text);
          $ta[0].dispatchEvent(new Event('input', { bubbles: true }));
          showToast('指令已载入');
        }
      } catch (e) { console.error('[GodPanel]', e); }
    }
    function showToast(msg) {
      const t = document.getElementById('toast-msg');
      if (t) { t.textContent = msg; t.classList.add('show'); setTimeout(() => t.classList.remove('show'), 1500); }
    }

    window.interactItem = function(action, safeName) {
        const name = decodeURIComponent(safeName);
        let cmd = '';
        if(action === 'equip') cmd = `[系统指令] 尝试将宝库中的物品【${name}】装备在自己身上。请在剧情中描写装备的过程。`;
        if(action === 'give') cmd = `[系统指令] 打算将宝库中的物品【${name}】赐予使徒。请询问我想给谁，并描写赐予的过程。`;
        if(action === 'repair') cmd = `[系统指令] 消耗神力，将物品【${name}】的耐久度完全修复。`;
        if(cmd) copyToInput(cmd);
    };

    function populateData() {
      const V = getAllVariables();
      const stats = _.get(V, 'stat_data', {});
      const god = stats.god_status || {};
      const world = stats.world_state || {};
      const apostles = stats.apostles || {};
      miraclesData = stats.miracles || {};
      const treasury = stats.treasury || {};

      $('#world-name').text(world.name || '神界·永恒圣域');
      $('#god-persona').text(god.current_persona || '至高神本尊');

      let modeRaw = god.play_mode;
      if (typeof modeRaw !== 'string') modeRaw = 'Hedonism';
      let modeKey = modeRaw.trim();

      const modeMap = {
        'Hedonism': { text: '享乐模式', class: 'mode-hedonism' },
        'hedonism': { text: '享乐模式', class: 'mode-hedonism' },
        'Adventure': { text: '冒险模式', class: 'mode-adventure' },
        'adventure': { text: '冒险模式', class: 'mode-adventure' },
        'Incognito': { text: '微服模式', class: 'mode-incognito' },
        'incognito': { text: '微服模式', class: 'mode-incognito' }
      };
      const curMode = modeMap[modeKey] || { text: modeKey || '未知模式', class: 'mode-unknown' };
      $('#mode-badge').text(curMode.text).attr('class', 'mode-badge ' + curMode.class);

      const isAdventure = (curMode.class === 'mode-adventure');

      if (isAdventure) {
        $('#nav-miracle').addClass('hidden-by-mode');
        $('#quick-miracle').addClass('hidden-by-mode');
        if ($('#tab-miracle').hasClass('active')) {
           $('.tab-btn').removeClass('active'); $('#nav-throne').addClass('active');
           $('.tab-content').removeClass('active'); $('#tab-throne').addClass('active');
        }
        $('#hp-block').show();
        const hp = god.hp || 100;
        $('#hp-val').text(hp + '/100');
        const $hpBar = $('#hp-bar');
        $hpBar.css('width', hp + '%').removeClass('hp hp-crit');
        if (hp <= 20) $hpBar.addClass('hp-crit'); else $hpBar.addClass('hp');
      } else {
        $('#nav-miracle').removeClass('hidden-by-mode');
        $('#quick-miracle').removeClass('hidden-by-mode');
        $('#hp-block').hide();
      }

      $('#chaos-val').text((world.chaos_level || 0) + '%');
      $('#chaos-bar').css('width', (world.chaos_level || 0) + '%');

      // 使徒列表
      const apostleList = Object.entries(apostles);
      const $aList = $('#apostle-list');
      $aList.empty();
      if (apostleList.length === 0) {
        $aList.html('<div style="text-align:center;color:#666;padding:20px;font-style:italic;">尚无使徒</div>');
      } else {
        apostleList.sort((a, b) => {
          if (a[1].location === 'Party' && b[1].location !== 'Party') return -1;
          if (b[1].location === 'Party' && a[1].location !== 'Party') return 1;
          return (b[1].love || 0) - (a[1].love || 0);
        });
        let aHtml = '';
        apostleList.forEach(([name, data]) => {
          const locText = (data.location === 'Party') ? '随行' : (data.location === 'Mission' ? '任务' : '神界');
          aHtml += `
            <div class="item-card">
              <div class="item-header">
                <span class="item-name">♛ ${name}</span>
                <span class="item-tag" style="${data.location === 'Party' ? 'color:var(--gold);border-color:var(--gold);box-shadow: 0 0 8px rgba(255, 215, 0, 0.3);' : ''}">${locText}</span>
              </div>
              <div class="apostle-stats">
                <div class="mini-stat"><div class="stat-label">爱</div><div style="color:var(--neon-pink);font-family:monospace;font-size:13px;font-weight:bold;">${data.love||0}</div></div>
                <div class="mini-stat"><div class="stat-label">从</div><div style="color:#bb86fc;font-family:monospace;font-size:13px;font-weight:bold;">${data.submission||0}</div></div>
                <div class="mini-stat"><div class="stat-label">忠</div><div style="color:var(--gold);font-family:monospace;font-size:13px;font-weight:bold;">${data.loyalty||0}</div></div>
              </div>
            </div>`;
        });
        $aList.append(aHtml);
      }
      $('#harem-count').text(apostleList.length + ' 人');

      // 宝库列表
      const treasuryList = Object.entries(treasury);
      const $tList = $('#treasury-list');
      $tList.empty();
      if (treasuryList.length === 0) {
        $tList.html('<div style="text-align:center;color:#666;padding:20px;font-style:italic;">宝库空空如也</div>');
      } else {
        let tHtml = '';
        treasuryList.forEach(([name, data]) => {
          const safeName = encodeURIComponent(name);
          const typeMap = { 'Weapon':'武器', 'Armor':'防具', 'Accessory':'饰品', 'Consumable':'消耗品' };
          const typeStr = typeMap[data.type] || '物品';
          const dur = (data.type === 'Consumable') ? 'N/A' : (data.durability || 0);

          let statusHtml = '';
          let borderColor = '#555';
          if(data.is_equipped) {
              statusHtml = '<span class="item-tag" style="color:#00f5d4; border-color:#00f5d4;">使用中</span>';
              borderColor = '#00f5d4';
          } else if(data.equipped_by && data.equipped_by !== 'None') {
              statusHtml = `<span class="item-tag" style="color:var(--neon-pink); border-color:var(--neon-pink);">${data.equipped_by} 装备</span>`;
              borderColor = 'var(--neon-pink)';
          } else {
              statusHtml = `<span class="item-tag">${data.rarity}</span>`;
          }

          let durHtml = '';
          if(data.type !== 'Consumable') {
              durHtml = `
              <div class="progress-container" style="margin: 4px 0;">
                <div class="progress-label" style="font-size:9px;"><span>耐久度</span><span>${dur}/100</span></div>
                <div class="progress-bar" style="height:4px;"><div class="progress-fill durability" style="width:${dur}%"></div></div>
              </div>`;
          }

          let modHtml = '';
          if(data.god_modifier && data.god_modifier !== 'None') {
              modHtml = `<span class="modifier-tag">✦ 魔改: ${data.god_modifier}</span>`;
          }

          tHtml += `
            <div class="item-card" style="border-left-color: ${borderColor};">
              <div class="item-header" style="margin-bottom:4px;">
                <span class="item-name" style="color: #fff;"><i class="fas fa-cube"></i> ${name} <span style="font-size:10px;color:#888;">[${typeStr}]</span></span>
                ${statusHtml}
              </div>
              ${durHtml}
              <div style="font-size: 11px; color: #ccc; padding: 4px; background: rgba(0,0,0,0.4); border-radius: 4px; line-height: 1.4;">
                ${data.description || '无描述'}
                ${modHtml}
              </div>
              <div class="equip-actions">
                <button class="equip-btn" onclick="interactItem('equip', '${safeName}')">装备</button>
                <button class="equip-btn" onclick="interactItem('give', '${safeName}')">赐予</button>
                ${(dur < 100 && data.type !== 'Consumable') ? `<button class="equip-btn" onclick="interactItem('repair', '${safeName}')">修复</button>` : ''}
              </div>
            </div>`;
        });
        $tList.append(tHtml);
      }
      $('#treasury-count').text(treasuryList.length + ' 件');

      // 神迹列表
      const miracleList = Object.entries(miraclesData);
      const $mList = $('#miracle-list');
      $mList.empty();
      if (miracleList.length === 0) {
        $mList.html('<div style="text-align:center;color:#666;padding:20px;font-style:italic;">尚无神迹</div>');
      } else {
        let mHtml = '';
        miracleList.forEach(([name, data]) => {
          const isActive = data.is_active !== false;
          const usesLeft = (data.uses_left >= 999 || !data.uses_left) ? '∞' : data.uses_left;
          const statusText = isActive ? '<span style="color:#00f5d4">激活</span>' : '<span style="color:#e63946">封印</span>';
          mHtml += `
            <div class="item-card" style="border-left-color: var(--neon-cyan);">
              <div class="item-header">
                <span class="item-name" style="color: var(--neon-cyan);"><i class="fas fa-bolt"></i> ${name}</span>
                <span class="item-tag">${statusText} | 余量: ${usesLeft}</span>
              </div>
              <div style="font-size: 11px; color: #ccc; padding: 6px; background: rgba(0,0,0,0.4); border-radius: 4px; line-height: 1.5;">
                ${data.description || '无描述'}
              </div>
            </div>`;
        });
        $mList.append(mHtml);
      }
      $('#miracle-count').text(miracleList.length + ' 种');
    }

    window.openMiracleModal = function() {
      const $body = $('#miracle-modal-body');
      $body.empty();
      $body.append(`
        <div class="cast-btn" onclick="castMiracle('Universal_Table_Flip')" style="border-color: var(--gold);">
          <div class="cast-title" style="color: var(--gold);"><i class="fas fa-fire"></i> 原始神权 (掀桌子) <span>无消耗</span></div>
          <div class="cast-desc">无视一切逻辑与规则，强制碾压当前困境。</div>
        </div>
      `);
      Object.entries(miraclesData).forEach(([name, data]) => {
        const isActive = data.is_active !== false;
        const uses = typeof data.uses_left === 'number' ? data.uses_left : 999;
        const usesDisplay = uses >= 999 ? '∞' : uses;
        const disabled = (!isActive || uses <= 0) ? 'disabled' : '';
        const tag = (!isActive) ? '[已封印]' : (uses <= 0 ? '[次数耗尽]' : `[余量: ${usesDisplay}]`);
        const safeName = encodeURIComponent(name);
        const safeDesc = encodeURIComponent(data.description || '');
        $body.append(`
          <div class="cast-btn ${disabled}" onclick="castMiracle('${safeName}', '${safeDesc}')">
            <div class="cast-title" style="color: var(--neon-cyan);"><i class="fas fa-bolt"></i> ${name} <span style="color:#aaa; font-weight:normal">${tag}</span></div>
            <div class="cast-desc">${data.description || ''}</div>
          </div>
        `);
      });
      $('#miracle-modal').addClass('show');
    };

    window.closeMiracleModal = function() { $('#miracle-modal').removeClass('show'); };

    window.castMiracle = function(safeName, safeDesc) {
      closeMiracleModal();
      if (safeName === 'Universal_Table_Flip') {
        copyToInput('[系统指令] 发动至高神权，无视逻辑强制修改现实/解决当前困境/显露神迹。请直接描写我如何用神力碾压一切，不需要判定。');
        return;
      }
      const name = decodeURIComponent(safeName);
      const desc = decodeURIComponent(safeDesc);
      const command = `[系统指令] 发动自创神迹：【${name}】。\n效果说明：${desc}\n请立刻描写我使用此神迹直接干涉现实的震撼过程，无需任何判定或阻碍。\n(同时请在UpdateVariable中将 miracles.${name}.uses_left 减 1)`;
      copyToInput(command);
    };

    window.rollDice = function() {
      const action = $('#dice-action').val().trim();
      const diff = parseInt($('#dice-diff').val()) || 50;
      if (!action) { showToast('请填写行动描述'); return; }
      const roll = Math.floor(Math.random() * 100) + 1;
      let result = '';
      if (roll <= 5) result = '💀 大失败';
      else if (roll < diff) result = '❌ 失败';
      else if (roll <= 89) result = '✅ 成功';
      else if (roll <= 95) result = '⭐ 大成功';
      else result = '👑 完美';
      const msg = `<命运骰点>🎲 1d100 = ${roll}</命运骰点>\\n行动：${action}\\n难度：${diff}\\n结果：${result}`;
      sendToTavern(msg);
      $('#dice-action').val('');
    }

    window.quickAction = function(type) {
      if(type === 'miracle') {
        openMiracleModal();
      } else {
        const texts = {
          'scan': '扫描当前世界的高价值目标',
          'descend': '降临到新世界',
          'rest': '在神界休息'
        };
        if (texts[type]) copyToInput(texts[type]);
      }
    }

    /* ====== 音乐与歌词系统 ====== */
    // 伊安哥哥注意：由于我不知道这首歌实际唱出每句歌词的准确秒数，
    // 下面括号里 [分:秒.毫秒] 的时间戳是我暂估的！
    // 你可以自己一边听一边修改这里的时间戳，让它完美同步！
    const rawLyrics = `
[00:00.00] · · ·
