[03:28.00] · · ·
    `;

    let lyricsData = [];
    let currentLyricIndex = -1;

    function parseLyrics(lrc) {
      const lines = lrc.split('\n');
      const timeExp = /\[(\d{2}):(\d{2}\.\d{2})\]/;
      const parsed = [];
      lines.forEach(line => {
        const match = timeExp.exec(line);
        if (match) {
          const minutes = parseInt(match[1], 10);
          const seconds = parseFloat(match[2]);
          const time = minutes * 60 + seconds;
          const text = line.replace(timeExp, '').trim();
          if (text) parsed.push({ time, text });
        }
      });
      return parsed.sort((a, b) => a.time - b.time);
    }

    function initLyrics() {
      lyricsData = parseLyrics(rawLyrics);
      const wrapper = document.getElementById('lyrics-wrapper');
      wrapper.innerHTML = '';
      lyricsData.forEach((item, index) => {
        const div = document.createElement('div');
        div.className = 'lyric-line';
        div.id = `lyric-${index}`;
        div.textContent = item.text;
        wrapper.appendChild(div);
      });
    }

    window.toggleGodMusic = function() {
      const audio = document.getElementById('god-bgm');
      const btn = document.getElementById('play-btn');
      if (audio.paused) {
        audio.play();
        btn.innerHTML = '<i class="fas fa-pause-circle"></i>';
      } else {
        audio.pause();
        btn.innerHTML = '<i class="fas fa-play-circle"></i>';
      }
    };

    window.changeGodVolume = function(val) {
      const audio = document.getElementById('god-bgm');
      if (audio) {
        audio.volume = val;
      }
    };

    function updateLyricsDisplay(currentTime) {
      if (lyricsData.length === 0) return;

      let newIndex = lyricsData.length - 1;
      for (let i = 0; i < lyricsData.length; i++) {
        if (currentTime < lyricsData[i].time) {
          newIndex = i - 1;
          break;
        }
      }

      if (newIndex !== currentLyricIndex && newIndex >= 0) {
        if (currentLyricIndex !== -1) {
          const oldLine = document.getElementById(`lyric-${currentLyricIndex}`);
          if (oldLine) oldLine.classList.remove('active');
        }

        const newLine = document.getElementById(`lyric-${newIndex}`);
        if (newLine) newLine.classList.add('active');
        currentLyricIndex = newIndex;

        // 自动滚动 (20是行高估值，将其滚动到中间)
        const wrapper = document.getElementById('lyrics-wrapper');
        const offset = -(newIndex * 20) + 20;
        wrapper.style.transform = `translateY(${offset}px)`;
      }
    }

    async function init() {
      $('.tab-btn').on('click', function() {
        if ($(this).hasClass('hidden-by-mode')) return;
        $('.tab-btn').removeClass('active'); $(this).addClass('active');
        $('.tab-content').removeClass('active'); $('#' + $(this).data('tab')).addClass('active');
      });
      $('#dice-action, #dice-diff').on('click', e => e.stopPropagation());

      const audio = document.getElementById('god-bgm');
      if(audio) {
        audio.volume = 0.3;
        // 绑定时间更新事件，驱动歌词滚动
        audio.addEventListener('timeupdate', () => {
          updateLyricsDisplay(audio.currentTime);
        });
      }

      initLyrics(); // 解析并渲染歌词

      await waitGlobalInitialized('Mvu');
      populateData();
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, populateData);
    }
    $(errorCatched(init));
  </script>
</head>
